  1→import type { StreamEvent } from "../../shared/contracts";
  2→import { jsonError } from "../http/response";
  3→import { logInfo, logWarn } from "../http/observability";
  4→
  5→type StreamState = {
  6→  queue: StreamEvent[];
  7→  controller?: ReadableStreamDefaultController<Uint8Array>;
  8→  finished: boolean;
  9→  keepAliveId?: ReturnType<typeof setInterval>;
 10→};
 11→
 12→const encoder = new TextEncoder();
 13→
 14→export type SseRegistry = {
 15→  registerMessage: (messageId: string) => void;
 16→  handleStreamRequest: (messageId: string) => Response;
 17→  emitEvent: (messageId: string, event: StreamEvent) => void;
 18→};
 19→
 20→export function createSseRegistry(): SseRegistry {
 21→  const streams = new Map<string, StreamState>();
 22→
 23→  function cleanupStream(messageId: string, reason: string): void {
 24→    const state = streams.get(messageId);
 25→    if (!state) {
 26→      return;
 27→    }
 28→
 29→    if (state.keepAliveId) {
 30→      clearInterval(state.keepAliveId);
 31→    }
 32→
 33→    streams.delete(messageId);
 34→    logInfo("sse.stream.closed", "SSE stream closed", { messageId, reason });
 35→  }
 36→
 37→  function encodeSse(event: StreamEvent): Uint8Array {
 38→    return encoder.encode(`data: ${JSON.stringify(event)}\n\n`);
 39→  }
 40→
 41→  return {
 42→    registerMessage(messageId: string): void {
 43→      streams.set(messageId, {
 44→        queue: [],
 45→        finished: false,
 46→      });
 47→    },
 48→
 49→    handleStreamRequest(messageId: string): Response {
 50→      const state = streams.get(messageId);
 51→      if (!state) {
 52→        logWarn("sse.stream.not_found", "SSE stream not found", { messageId });
 53→        return jsonError("stream not found", 404);
 54→      }
 55→
 56→      const stream = new ReadableStream<Uint8Array>({
 57→        start(controller) {
 58→          state.controller = controller;
 59→          logInfo("sse.stream.opened", "SSE stream opened", { messageId, queuedEventCount: state.queue.length });
 60→
 61→          for (const event of state.queue) {
 62→            controller.enqueue(encodeSse(event));
 63→          }
 64→          state.queue = [];
 65→
 66→          if (state.finished) {
 67→            controller.close();
 68→            cleanupStream(messageId, "finished_before_start");
 69→            return;
 70→          }
 71→
 72→          state.keepAliveId = setInterval(() => {
 73→            controller.enqueue(encoder.encode(": keep-alive\n\n"));
 74→          }, 15_000);
 75→        },
 76→        cancel() {
 77→          cleanupStream(messageId, "client_cancelled");
 78→        },
 79→      });
 80→
 81→      return new Response(stream, {
 82→        headers: {
 83→          "Content-Type": "text/event-stream",
 84→          "Cache-Control": "no-cache, no-transform",
 85→          Connection: "keep-alive",
 86→          "Access-Control-Allow-Origin": "*",
 87→        },
 88→      });
 89→    },
 90→
 91→    emitEvent(messageId: string, event: StreamEvent): void {
 92→      const state = streams.get(messageId);
 93→      if (!state) {
 94→        return;
 95→      }
 96→
 97→      if (state.controller) {
 98→        state.controller.enqueue(encodeSse(event));
 99→      } else {
100→        state.queue.push(event);
101→      }
102→
103→      if (event.type === "done" || event.type === "error") {
104→        state.finished = true;
105→        if (state.controller) {
106→          state.controller.close();
107→          cleanupStream(messageId, event.type === "done" ? "completed" : "error_event");
108→        }
109→      }
110→    },
111→  };
112→}
