 82→    model: input.deps.pmAgentModel,
 83→    instructions: system,
 84→    tools: createPmTools(input.deps),
 85→    output: Output.object({ schema: pmAgentResultSchema }),
 86→    experimental_context: { ...input.context, actor: "pm_agent" as const, humanPresent: input.context.humanPresent ?? true },
 87→    stopWhen: stepCountIs(6),
 88→  });
 89→
 90→  const startedAt = performance.now();
 91→
 92→  const result = await agent.generate({
 93→    prompt: [
 94→      "You are handling a PM request.",
 95→      `Intent: ${input.intent}`,
 96→      INTENT_INSTRUCTIONS[input.intent],
 97→      "IMPORTANT: You MUST call your tools (create_work_item, suggest_work_items, etc.) BEFORE generating your final output. Do NOT skip tool calls — your output summary must reflect actual tool execution results.",
 98→      "Context:",
 99→      input.conversationContext,
100→    ].join("\n"),
101→  });
102→
103→  const totalDurationMs = Math.round(performance.now() - startedAt);
104→
105→  if (!result.output) {
106→    throw new Error("pm agent did not produce structured output");
107→  }
108→
109→  const extracted_entities: ExtractedEntity[] = [];
110→  const extracted_relationships: ExtractedRelationship[] = [];
111→  const traceSteps: SubagentTraceStep[] = [];
112→
113→  for (const step of result.steps) {
114→    if (step.text?.trim()) {
115→      traceSteps.push({ type: "text", text: step.text.trim() });
116→    }
117→
118→    for (const toolResult of step.toolResults) {
119→      traceSteps.push({
120→        type: "tool_call",
121→        toolName: toolResult.toolName,
122→        argsJson: JSON.stringify(toolResult.input),
123→        resultJson: JSON.stringify(toolResult.output),
124→      });
125→
126→      const res = toolResult.output as Record<string, unknown> | undefined;
127→      if (res) {
128→        if (Array.isArray(res.extracted_entities)) {
129→          extracted_entities.push(...(res.extracted_entities as ExtractedEntity[]));
130→        }
131→        if (Array.isArray(res.extracted_relationships)) {
132→          extracted_relationships.push(...(res.extracted_relationships as ExtractedRelationship[]));
133→        }
134→      }
135→    }
136→  }
137→
138→  return {
139→    ...result.output,
140→    extracted_entities,
141→    extracted_relationships,
142→    trace: {
143→      agentId: "pm_agent",
144→      intent: input.intent,
145→      steps: traceSteps,
146→      totalDurationMs,
147→    },
148→  };
149→}
