510→  // If task-scoped, link session to task and auto-promote status
511→  if (input.taskId) {
512→    const taskRecord = new RecordId("task", requireRawId(input.taskId, "task_id"));
513→    const task = await input.surreal.select<TaskRow>(taskRecord);
514→    if (!task) {
515→      throw new Error(`task not found: ${input.taskId}`);
516→    }
