741→function levenshteinSimilarity(a: string, b: string): number {
742→  if (a === b) return 1;
743→  const longer = a.length > b.length ? a : b;
744→  const shorter = a.length > b.length ? b : a;
745→  if (longer.length === 0) return 1;
746→
747→  const costs: number[] = [];
748→  for (let i = 0; i <= longer.length; i++) {
749→    let lastValue = i;
750→    for (let j = 0; j <= shorter.length; j++) {
751→      if (i === 0) {
752→        costs[j] = j;
753→      } else if (j > 0) {
754→        let newValue = costs[j - 1];
755→        if (longer.charAt(i - 1) !== shorter.charAt(j - 1)) {
756→          newValue = Math.min(Math.min(newValue, lastValue), costs[j]) + 1;
757→        }
758→        costs[j - 1] = lastValue;
759→        lastValue = newValue;
760→      }
761→    }
762→    if (i > 0) costs[shorter.length] = lastValue;
763→  }
764→
765→  return (longer.length - costs[shorter.length]) / longer.length;
766→}
