 34→export function loadServerConfig(): ServerConfig {
 35→  const openRouterApiKey = requireEnv("OPENROUTER_API_KEY");
 36→
 37→  const extractionStoreThreshold = parseUnitInterval(
 38→    requireEnv("EXTRACTION_STORE_THRESHOLD"),
 39→    "EXTRACTION_STORE_THRESHOLD",
 40→  );
 41→
 42→  const extractionDisplayThreshold = parseUnitInterval(
 43→    requireEnv("EXTRACTION_DISPLAY_THRESHOLD"),
 44→    "EXTRACTION_DISPLAY_THRESHOLD",
 45→  );
 46→
 47→  if (extractionDisplayThreshold < extractionStoreThreshold) {
 48→    throw new Error("EXTRACTION_DISPLAY_THRESHOLD must be greater than or equal to EXTRACTION_STORE_THRESHOLD");
 49→  }
 50→
 51→  const chatAgentModelId = requireEnv("CHAT_AGENT_MODEL");
 52→  const extractionModelId = requireEnv("EXTRACTION_MODEL");
