 71→  const githubClientSecret = requireEnv("GITHUB_CLIENT_SECRET");
 72→
 73→  return {
 74→    openRouterApiKey,
 75→    chatAgentModelId,
 76→    extractionModelId,
 77→    pmAgentModelId,
 78→    analyticsAgentModelId,
 79→    embeddingModelId,
 80→    embeddingDimension,
 81→    extractionStoreThreshold,
