 98→function requireEnv(name: string): string {
 99→  const value = Bun.env[name];
100→  if (!value || value.trim().length === 0) {
101→    throw new Error(`${name} is required`);
102→  }
103→
104→  return value;
105→}
106→
107→function parsePositiveInteger(value: string, envName: string): number {
108→  const parsed = Number(value);
109→  if (!Number.isInteger(parsed) || parsed < 1) {
110→    throw new Error(`${envName} must be a positive integer`);
111→  }
112→  return parsed;
113→}
114→
115→function parseUnitInterval(value: string, envName: string): number {
116→  const parsed = Number(value);
117→  if (!Number.isFinite(parsed) || parsed < 0 || parsed > 1) {
118→    throw new Error(`${envName} must be a number between 0 and 1`);
119→  }
120→
121→  return parsed;
122→}
123→
124→function parseOpenRouterReasoning(): OpenRouterReasoningOptions | undefined {
125→  const effortValue = Bun.env.OPENROUTER_REASONING_EFFORT;
126→  const maxTokensValue = Bun.env.OPENROUTER_REASONING_MAX_TOKENS;
127→
128→  if (!effortValue && !maxTokensValue) {
129→    return undefined;
130→  }
131→
132→  const reasoning: OpenRouterReasoningOptions = {};
133→
134→  if (effortValue) {
135→    const allowedEfforts: OpenRouterReasoningEffort[] = ["xhigh", "high", "medium", "low", "minimal", "none"];
136→
137→    if (!allowedEfforts.includes(effortValue as OpenRouterReasoningEffort)) {
138→      throw new Error("OPENROUTER_REASONING_EFFORT must be one of xhigh, high, medium, low, minimal, none");
139→    }
140→    reasoning.effort = effortValue as OpenRouterReasoningEffort;
141→  }
142→
143→  if (maxTokensValue) {
144→    const parsed = Number(maxTokensValue);
145→    if (!Number.isFinite(parsed) || parsed < 1) {
146→      throw new Error("OPENROUTER_REASONING_MAX_TOKENS must be a positive number");
147→    }
148→    reasoning.max_tokens = parsed;
149→  }
150→
151→  return reasoning;
152→}
