 63→/** List active decisions, optionally scoped to a project and/or area */
 64→export async function listProjectDecisions(input: {
 65→  surreal: Surreal;
 66→  workspaceRecord: RecordId<"workspace", string>;
 67→  projectRecord?: RecordId<"project", string>;
 68→  area?: string;
 69→}): Promise<{
 70→  confirmed: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
 71→  provisional: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
 72→  contested: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
 73→}> {
 74→  const projectFilter = input.projectRecord
 75→    ? `AND id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project)`
 76→    : "";
 77→  const areaFilter = input.area
 78→    ? `AND category = $area`
 79→    : "";
 80→
 81→  const [rows] = await input.surreal
 82→    .query<[DecisionRow[]]>(
 83→      `SELECT id, summary, status, rationale, decided_at, category, priority, created_at
 84→       FROM decision
 85→       WHERE workspace = $workspace
 86→         ${projectFilter}
 87→         ${areaFilter}
 88→       ORDER BY created_at DESC LIMIT 50;`,
 89→      {
 90→        workspace: input.workspaceRecord,
 91→        ...(input.projectRecord ? { project: input.projectRecord } : {}),
 92→        ...(input.area ? { area: input.area } : {}),
 93→      },
 94→    )
 95→    .collect<[DecisionRow[]]>();
 96→
 97→  type DecisionItem = { id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string };
 98→  const confirmed: DecisionItem[] = [];
 99→  const provisional: DecisionItem[] = [];
100→  const contested: DecisionItem[] = [];
101→
102→  for (const d of rows) {
103→    const item: DecisionItem = {
104→      id: toRawId(d.id),
105→      summary: d.summary,
106→      status: d.status,
107→      ...(d.rationale ? { rationale: d.rationale } : {}),
108→      ...(d.decided_at ? { decided_at: toIso(d.decided_at) } : {}),
109→      ...(d.category ? { category: d.category } : {}),
110→    };
111→
112→    if (d.status === "contested") contested.push(item);
113→    else if (d.status === "provisional" || d.status === "inferred") provisional.push(item);
114→    else if (d.status === "confirmed") confirmed.push(item);
115→  }
116→
117→  return { confirmed, provisional, contested };
118→}
