120→/** Get task dependency tree (recursive) */
121→export async function getTaskDependencyTree(input: {
122→  surreal: Surreal;
123→  workspaceRecord: RecordId<"workspace", string>;
124→  taskRecord: RecordId<"task", string>;
125→}): Promise<{
126→  task: { id: string; title: string; status: string };
127→  dependencies: Array<{ id: string; title: string; status: string; resolved: boolean }>;
128→  dependents: Array<{ id: string; title: string; status: string }>;
129→  subtasks: Array<{ id: string; title: string; status: string }>;
130→}> {
131→  const task = await input.surreal.select<TaskRow>(input.taskRecord);
132→  if (!task) throw new Error(`task not found: ${input.taskRecord.id}`);
133→  if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
134→    throw new Error("task is outside the current workspace scope");
135→  }
136→
137→  const query = `
138→    -- Tasks this task depends on
139→    SELECT id, title, status
140→    FROM task
141→    WHERE id IN (SELECT VALUE out FROM depends_on WHERE \`in\` = $task);
142→
143→    -- Tasks that depend on this task
144→    SELECT id, title, status
145→    FROM task
146→    WHERE id IN (SELECT VALUE \`in\` FROM depends_on WHERE out = $task);
147→
148→    -- Subtasks
149→    SELECT id, title, status
150→    FROM task
151→    WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $task)
152→    ORDER BY created_at ASC;
153→  `;
154→
155→  const results = await input.surreal
156→    .query<[DependencyRow[], DependencyRow[], SubtaskRow[]]>(query, { task: input.taskRecord })
157→    .collect<[DependencyRow[], DependencyRow[], SubtaskRow[]]>();
158→
159→  const [deps, dependents, subtasks] = results;
160→
161→  return {
162→    task: { id: toRawId(task.id), title: task.title, status: task.status },
163→    dependencies: deps.map((d) => ({
164→      id: toRawId(d.id),
165→      title: d.title,
166→      status: d.status,
167→      resolved: d.status === "done" || d.status === "completed",
168→    })),
169→    dependents: dependents.map((d) => ({ id: toRawId(d.id), title: d.title, status: d.status })),
170→    subtasks: subtasks.map((s) => ({ id: toRawId(s.id), title: s.title, status: s.status })),
171→  };
172→}
