241→/** List recent changes since a timestamp */
242→export async function listRecentChanges(input: {
243→  surreal: Surreal;
244→  workspaceRecord: RecordId<"workspace", string>;
245→  projectRecord?: RecordId<"project", string>;
246→  since: string;
247→}): Promise<Array<{ entity_type: string; entity_name: string; change_type: string; changed_at: string }>> {
248→  const sinceDate = new Date(input.since);
249→
250→  const projectFilter = input.projectRecord
251→    ? `AND id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project)`
252→    : "";
253→
254→  const query = `
255→    LET $recent_decisions = SELECT "decision" AS entity_type, summary AS entity_name, status AS change_type, updated_at AS changed_at
256→    FROM decision
257→    WHERE workspace = $workspace ${projectFilter} AND updated_at > $since
258→    ORDER BY updated_at DESC LIMIT 20;
259→
260→    LET $recent_tasks = SELECT "task" AS entity_type, title AS entity_name, status AS change_type, updated_at AS changed_at
261→    FROM task
262→    WHERE workspace = $workspace ${projectFilter} AND updated_at > $since
263→    ORDER BY updated_at DESC LIMIT 20;
264→
265→    LET $recent_questions = SELECT "question" AS entity_type, text AS entity_name, status AS change_type, updated_at AS changed_at
266→    FROM question
267→    WHERE workspace = $workspace ${projectFilter} AND updated_at > $since
268→    ORDER BY updated_at DESC LIMIT 20;
269→
270→    RETURN array::flatten([$recent_decisions, $recent_tasks, $recent_questions]);
271→  `;
272→
273→  const results = await input.surreal
274→    .query<[null, null, null, EntityChangeRow[]]>(query, {
