289→/** Create a subtask with semantic dedup */
290→export async function createSubtask(input: {
291→  surreal: Surreal;
292→  parentTaskRecord: RecordId<"task", string>;
293→  title: string;
294→  workspaceRecord: RecordId<"workspace", string>;
295→  category?: string;
296→  rationale?: string;
297→}): Promise<{ task_id: string; parent_task_id: string; already_existed: boolean }> {
298→  // Check for existing similar subtasks (semantic dedup by title)
299→  const normalizedTitle = input.title.toLowerCase().trim();
300→
301→  const [existingRows] = await input.surreal
302→    .query<[SubtaskRow[]]>(
303→      `SELECT id, title, status
304→       FROM task
305→       WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $parent)
306→       ORDER BY created_at ASC;`,
307→      { parent: input.parentTaskRecord },
308→    )
309→    .collect<[SubtaskRow[]]>();
310→
311→  // Simple dedup: check if any existing subtask title is very similar
312→  for (const existing of existingRows) {
313→    const existingNormalized = existing.title.toLowerCase().trim();
314→    if (existingNormalized === normalizedTitle || levenshteinSimilarity(existingNormalized, normalizedTitle) > 0.85) {
315→      return {
316→        task_id: toRawId(existing.id),
317→        parent_task_id: toRawId(input.parentTaskRecord),
318→        already_existed: true,
319→      };
320→    }
321→  }
322→
323→  // Get parent task's category if not specified
324→  const parentTask = await input.surreal.select<TaskRow>(input.parentTaskRecord);
325→  if (!parentTask) throw new Error(`parent task not found: ${input.parentTaskRecord.id}`);
326→  if ((parentTask.workspace.id as string) !== (input.workspaceRecord.id as string)) {
327→    throw new Error("parent task is outside the current workspace scope");
328→  }
329→
330→  const now = new Date();
331→  const taskRecord = new RecordId("task", randomUUID());
332→
333→  await input.surreal.create(taskRecord).content({
334→    title: input.title,
335→    status: "todo",
336→    created_at: now,
337→    updated_at: now,
338→    workspace: input.workspaceRecord,
339→    ...(input.category ? { category: input.category } : parentTask.category ? { category: parentTask.category } : {}),
340→    ...(input.rationale ? { description: input.rationale } : {}),
341→  });
342→
343→  // Create subtask_of edge
344→  await input.surreal
345→    .relate(taskRecord, new RecordId("subtask_of", randomUUID()), input.parentTaskRecord, {
346→      added_at: now,
347→    })
348→    .output("after");
349→
350→  // Copy belongs_to edges from parent (inherit project/feature)
351→  const [parentBelongsTo] = await input.surreal
352→    .query<[Array<{ out: RecordId }>]>(
353→      "SELECT out FROM belongs_to WHERE `in` = $parent;",
354→      { parent: input.parentTaskRecord },
355→    )
356→    .collect<[Array<{ out: RecordId }>]>();
357→
358→  for (const edge of parentBelongsTo) {
359→    await input.surreal
360→      .relate(taskRecord, new RecordId("belongs_to", randomUUID()), edge.out, {
361→        added_at: now,
362→      })
363→      .output("after");
364→  }
365→
366→  return {
367→    task_id: toRawId(taskRecord),
368→    parent_task_id: toRawId(input.parentTaskRecord),
369→    already_existed: false,
370→  };
371→}
