532→/** End an agent session with summary */
533→export async function endAgentSession(input: {
534→  surreal: Surreal;
535→  workspaceRecord: RecordId<"workspace", string>;
536→  sessionId: string;
537→  summary: string;
538→  decisionsMade?: string[];
539→  questionsAsked?: string[];
540→  tasksProgressed?: Array<{ task_id: string; from_status: string; to_status: string }>;
541→  filesChanged?: Array<{ path: string; change_type: string }>;
542→  observationsLogged?: string[];
543→}): Promise<{ session_id: string; ended: boolean }> {
544→  const now = new Date();
545→  const sessionRecord = new RecordId("agent_session", requireRawId(input.sessionId, "session_id"));
546→  const session = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(sessionRecord);
547→  if (!session) {
548→    throw new Error(`session not found: ${input.sessionId}`);
549→  }
550→  if ((session.workspace.id as string) !== (input.workspaceRecord.id as string)) {
551→    throw new Error("session is outside the current workspace scope");
552→  }
553→
554→  await input.surreal.update(sessionRecord).merge({
555→    ended_at: now,
556→    summary: input.summary,
557→    ...(input.decisionsMade?.length
558→      ? { decisions_made: input.decisionsMade.map((id) => new RecordId("decision", requireRawId(id, "decisions_made[]"))) }
559→      : {}),
560→    ...(input.questionsAsked?.length
561→      ? { questions_asked: input.questionsAsked.map((id) => new RecordId("question", requireRawId(id, "questions_asked[]"))) }
562→      : {}),
563→    ...(input.tasksProgressed?.length
564→      ? {
565→          tasks_progressed: input.tasksProgressed.map((t) => ({
566→            task_id: new RecordId("task", requireRawId(t.task_id, "tasks_progressed[].task_id")),
567→            from_status: t.from_status,
568→            to_status: t.to_status,
569→          })),
570→        }
571→      : {}),
572→    ...(input.filesChanged?.length ? { files_changed: input.filesChanged } : {}),
573→    ...(input.observationsLogged?.length
574→      ? { observations_logged: input.observationsLogged.map((id) => new RecordId("observation", requireRawId(id, "observations_logged[]"))) }
575→      : {}),
576→  });
577→
578→  // Create session -> entity edges
579→  if (input.decisionsMade?.length) {
580→    for (const decisionId of input.decisionsMade) {
581→      const rawDecisionId = requireRawId(decisionId, "decisions_made[]");
582→      await input.surreal
583→        .relate(sessionRecord, new RecordId("produced", randomUUID()), new RecordId("decision", rawDecisionId), {
584→          added_at: now,
585→        })
586→        .output("after");
587→    }
588→  }
589→
590→  if (input.questionsAsked?.length) {
591→    for (const questionId of input.questionsAsked) {
592→      const rawQuestionId = requireRawId(questionId, "questions_asked[]");
593→      await input.surreal
594→        .relate(sessionRecord, new RecordId("asked", randomUUID()), new RecordId("question", rawQuestionId), {
595→          added_at: now,
596→        })
597→        .output("after");
598→    }
599→  }
600→
601→  if (input.tasksProgressed?.length) {
602→    for (const t of input.tasksProgressed) {
603→      const rawTaskId = requireRawId(t.task_id, "tasks_progressed[].task_id");
604→      await input.surreal
605→        .relate(sessionRecord, new RecordId("progressed", randomUUID()), new RecordId("task", rawTaskId), {
606→          from_status: t.from_status,
607→          to_status: t.to_status,
608→          added_at: now,
609→        })
610→        .output("after");
611→    }
612→  }
613→
614→  return { session_id: toRawId(sessionRecord), ended: true };
615→}
