617→/** Log a git commit to the graph */
618→export async function logCommit(input: {
619→  surreal: Surreal;
620→  workspaceRecord: RecordId<"workspace", string>;
621→  projectRecord?: RecordId<"project", string>;
622→  sha: string;
623→  message: string;
624→  author: string;
625→  taskUpdates?: Array<{ task_id: string; new_status: string }>;
626→  relatedTaskIds?: string[];
627→  decisionsDetected?: Array<{ name: string; rationale: string }>;
628→}): Promise<{ commit_id: string; tasks_updated: number; tasks_linked: number; decisions_created: number }> {
629→  const now = new Date();
630→  const commitRecord = new RecordId("git_commit", randomUUID());
631→
632→  await input.surreal.create(commitRecord).content({
633→    sha: input.sha,
634→    message: input.message,
635→    author_name: input.author,
636→    workspace: input.workspaceRecord,
637→    authored_at: now,
638→    created_at: now,
639→  });
640→
641→  // Update task statuses
642→  let tasksUpdated = 0;
643→  if (input.taskUpdates?.length) {
644→    for (const update of input.taskUpdates) {
645→      const taskRecord = new RecordId("task", requireRawId(update.task_id, "task_updates[].task_id"));
646→      const task = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(taskRecord);
647→      if (!task) {
648→        throw new Error(`task not found: ${update.task_id}`);
649→      }
650→      if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
651→        throw new Error("task update is outside the current workspace scope");
652→      }
653→      await input.surreal.update(taskRecord).merge({
654→        status: update.new_status,
655→        updated_at: now,
656→      });
657→      tasksUpdated++;
658→    }
659→  }
660→
661→  // Link related tasks to this commit
662→  const linkedTaskIds = new Set<string>();
663→  // Include tasks from task_updates
664→  if (input.taskUpdates?.length) {
665→    for (const update of input.taskUpdates) {
666→      linkedTaskIds.add(requireRawId(update.task_id, "task_updates[].task_id"));
667→    }
668→  }
669→  // Include explicitly declared related tasks
670→  if (input.relatedTaskIds?.length) {
671→    for (const taskId of input.relatedTaskIds) {
672→      linkedTaskIds.add(requireRawId(taskId, "related_task_ids[]"));
673→    }
674→  }
675→  for (const taskId of linkedTaskIds) {
676→    const taskRecord = new RecordId("task", taskId);
677→    const task = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(taskRecord);
678→    if (!task) {
679→      throw new Error(`task not found: ${taskId}`);
680→    }
681→    if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
682→      throw new Error("task link is outside the current workspace scope");
683→    }
684→    await input.surreal
685→      .relate(taskRecord, new RecordId("implemented_by", randomUUID()), commitRecord, {
686→        commit_sha: input.sha,
687→        linked_at: now,
688→      })
689→      .output("after");
690→  }
691→
692→  // Create provisional decisions if flagged
693→  let decisionsCreated = 0;
694→  if (input.decisionsDetected?.length) {
695→    for (const decision of input.decisionsDetected) {
696→      const decisionRecord = new RecordId("decision", randomUUID());
697→      await input.surreal.create(decisionRecord).content({
698→        summary: decision.name,
699→        rationale: decision.rationale,
700→        status: "provisional",
701→        decided_by_name: "code-agent",
702→        workspace: input.workspaceRecord,
703→        source_commit: commitRecord,
704→        created_at: now,
705→        updated_at: now,
706→      });
707→
708→      // Link decision to project (if known)
709→      if (input.projectRecord) {
710→        await input.surreal
711→          .relate(decisionRecord, new RecordId("belongs_to", randomUUID()), input.projectRecord, {
712→            added_at: now,
713→          })
714→          .output("after");
715→      }
716→
717→      // Create implemented_by edge
718→      await input.surreal
719→        .relate(decisionRecord, new RecordId("implemented_by", randomUUID()), commitRecord, {
720→          commit_sha: input.sha,
721→          linked_at: now,
722→        })
723→        .output("after");
724→
725→      decisionsCreated++;
726→    }
727→  }
728→
729→  return {
730→    commit_id: toRawId(commitRecord),
731→    tasks_updated: tasksUpdated,
732→    tasks_linked: linkedTaskIds.size,
733→    decisions_created: decisionsCreated,
734→  };
735→}
