473→DEFINE FUNCTION fn::entity_search_workspace($q: string, $limit: int, $workspace: record<workspace>) {
474→  LET $query = string::lowercase(string::trim($q));
475→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
476→
477→  LET $task_rows = SELECT
478→    id,
479→    "task" AS kind,
480→    title AS text,
481→    extraction_confidence AS confidence,
482→    source_message AS sourceMessage,
483→    priority,
484→    created_at
485→  FROM task
486→  WHERE workspace = $workspace
487→    AND extraction_confidence != NONE
488→    AND string::contains(string::lowercase(title), $query)
489→  ORDER BY created_at DESC
490→  LIMIT $safe_limit;
491→
492→  LET $decision_rows = SELECT
493→    id,
494→    "decision" AS kind,
495→    summary AS text,
496→    extraction_confidence AS confidence,
497→    source_message AS sourceMessage,
498→    priority,
499→    created_at
500→  FROM decision
501→  WHERE workspace = $workspace
502→    AND extraction_confidence != NONE
503→    AND string::contains(string::lowercase(summary), $query)
504→  ORDER BY created_at DESC
505→  LIMIT $safe_limit;
506→
507→  LET $question_rows = SELECT
508→    id,
509→    "question" AS kind,
510→    text AS text,
511→    extraction_confidence AS confidence,
512→    source_message AS sourceMessage,
513→    priority,
514→    created_at
515→  FROM question
516→  WHERE workspace = $workspace
517→    AND extraction_confidence != NONE
518→    AND string::contains(string::lowercase(text), $query)
519→  ORDER BY created_at DESC
520→  LIMIT $safe_limit;
521→
522→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
523→};
524→
525→DEFINE FUNCTION fn::entity_search_project($q: string, $limit: int, $workspace: record<workspace>, $project: record<project>) {
526→  LET $query = string::lowercase(string::trim($q));
527→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
528→  LET $project_entity_ids = SELECT VALUE `in` FROM belongs_to WHERE out = $project;
529→
530→  LET $task_rows = SELECT
531→    id,
532→    "task" AS kind,
533→    title AS text,
534→    extraction_confidence AS confidence,
535→    source_message AS sourceMessage,
536→    priority,
537→    created_at
538→  FROM task
539→  WHERE workspace = $workspace
540→    AND extraction_confidence != NONE
541→    AND id IN $project_entity_ids
542→    AND string::contains(string::lowercase(title), $query)
543→  ORDER BY created_at DESC
544→  LIMIT $safe_limit;
545→
546→  LET $decision_rows = SELECT
547→    id,
548→    "decision" AS kind,
549→    summary AS text,
550→    extraction_confidence AS confidence,
551→    source_message AS sourceMessage,
552→    priority,
553→    created_at
554→  FROM decision
555→  WHERE workspace = $workspace
556→    AND extraction_confidence != NONE
557→    AND id IN $project_entity_ids
558→    AND string::contains(string::lowercase(summary), $query)
559→  ORDER BY created_at DESC
560→  LIMIT $safe_limit;
561→
562→  LET $question_rows = SELECT
563→    id,
564→    "question" AS kind,
565→    text AS text,
566→    extraction_confidence AS confidence,
567→    source_message AS sourceMessage,
568→    priority,
569→    created_at
570→  FROM question
571→  WHERE workspace = $workspace
572→    AND extraction_confidence != NONE
573→    AND id IN $project_entity_ids
574→    AND string::contains(string::lowercase(text), $query)
575→  ORDER BY created_at DESC
576→  LIMIT $safe_limit;
577→
578→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
579→};
