581→DEFINE FUNCTION fn::conversation_recent($conversation: record<conversation>, $limit: int) {
582→  LET $safe_limit = math::min([math::max([$limit, 1]), 50]);
583→  RETURN SELECT id, role, text, createdAt
584→  FROM message
585→  WHERE conversation = $conversation
586→  ORDER BY createdAt DESC
587→  LIMIT $safe_limit;
588→};
