  1→import { existsSync, mkdirSync, statSync } from "node:fs";
  2→import { join, dirname, resolve } from "node:path";
  3→import { homedir } from "node:os";
  4→
  5→function getBrainDir() { return process.env.BRAIN_CONFIG_DIR ?? join(homedir(), ".brain"); }
  6→function getConfigPath() { return join(getBrainDir(), "config.json"); }
  7→
  8→/** Resolved config for a single repo — shape consumed by BrainHttpClient and all commands. */
  9→export type BrainConfig = {
 10→  server_url: string;
 11→  workspace: string;
 12→  client_id: string;
 13→  access_token: string;
 14→  refresh_token: string;
 15→  token_expires_at: number;
 16→};
 17→
 18→/** Per-repo auth entry in ~/.brain/config.json */
 19→export type RepoConfig = {
 20→  workspace: string;
 21→  client_id: string;
 22→  access_token: string;
 23→  refresh_token: string;
 24→  token_expires_at: number;
 25→};
 26→
 27→/** Root shape of ~/.brain/config.json */
 28→export type BrainGlobalConfig = {
 29→  server_url: string;
 30→  repos: Record<string, RepoConfig>;
 31→};
 32→
 33→// ---------------------------------------------------------------------------
 34→// Git root
 35→// ---------------------------------------------------------------------------
 36→
 37→/**
 38→ * Find the main repository root from any path, including worktrees.
 39→ *
 40→ * In a regular repo, `.git` is a directory → that dir is the root.
 41→ * In a worktree, `.git` is a file containing `gitdir: /path/to/main/.git/worktrees/<name>`.
 42→ * We follow the pointer back to the main repo so all worktrees share one config key.
 43→ */
 44→export function findGitRoot(from: string): string | undefined {
 45→  let dir = from;
 46→  while (dir !== "/") {
 47→    const gitPath = join(dir, ".git");
 48→    if (existsSync(gitPath)) {
 49→      if (statSync(gitPath).isFile()) {
 50→        return resolveWorktreeMainRoot(gitPath) ?? dir;
 51→      }
 52→      return dir;
 53→    }
 54→    dir = dirname(dir);
 55→  }
 56→  return undefined;
 57→}
 58→
 59→/** Read a worktree .git file and resolve to the main repo root. */
 60→function resolveWorktreeMainRoot(gitFile: string): string | undefined {
 61→  try {
 62→    const content = Bun.file(gitFile).textSync().trim();
 63→    const match = content.match(/^gitdir:\s*(.+)$/);
 64→    if (!match) return undefined;
 65→
 66→    const gitdir = resolve(dirname(gitFile), match[1]);
 67→    const dotGit = gitdir.replace(/\/worktrees\/[^/]+$/, "");
 68→    return dirname(dotGit);
 69→  } catch {
 70→    return undefined;
 71→  }
 72→}
 73→
 74→// ---------------------------------------------------------------------------
 75→// Global config (~/.brain/config.json)
 76→// ---------------------------------------------------------------------------
 77→
 78→function ensureBrainDir(): void {
 79→  const dir = getBrainDir();
 80→  if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
 81→}
 82→
 83→export async function loadGlobalConfig(): Promise<BrainGlobalConfig | undefined> {
 84→  const file = Bun.file(getConfigPath());
 85→  if (!(await file.exists())) return undefined;
 86→  try {
 87→    return await file.json() as BrainGlobalConfig;
 88→  } catch {
 89→    return undefined;
 90→  }
 91→}
 92→
 93→export async function saveGlobalConfig(config: BrainGlobalConfig): Promise<void> {
 94→  ensureBrainDir();
 95→  await Bun.write(getConfigPath(), JSON.stringify(config, null, 2) + "\n");
 96→}
 97→
 98→/** Upsert a repo entry in the global config. Creates the file if needed. */
 99→export async function saveRepoConfig(serverUrl: string, gitRoot: string, repo: RepoConfig): Promise<void> {
100→  const global = (await loadGlobalConfig()) ?? { server_url: serverUrl, repos: {} };
101→  global.server_url = serverUrl;
102→  global.repos[gitRoot] = repo;
103→  await saveGlobalConfig(global);
104→}
105→
106→// ---------------------------------------------------------------------------
107→// Resolved config (what consumers use)
108→// ---------------------------------------------------------------------------
109→
110→/** Resolve BrainConfig for the current repo from ~/.brain/config.json.
111→ *  The server URL can be overridden via the BRAIN_SERVER_URL env var. */
112→export async function loadConfig(): Promise<BrainConfig | undefined> {
113→  const gitRoot = findGitRoot(process.cwd());
114→  const global = await loadGlobalConfig();
115→  if (global && gitRoot && global.repos[gitRoot]) {
116→    const repo = global.repos[gitRoot];
117→    const serverUrl = process.env.BRAIN_SERVER_URL ?? global.server_url;
118→    return {
119→      server_url: serverUrl,
120→      workspace: repo.workspace,
121→      client_id: repo.client_id,
122→      access_token: repo.access_token,
123→      refresh_token: repo.refresh_token,
124→      token_expires_at: repo.token_expires_at,
125→    };
126→  }
127→  return undefined;
128→}
129→
130→export async function requireConfig(): Promise<BrainConfig> {
131→  const config = await loadConfig();
132→  if (!config) {
133→    console.error("Brain not configured. Run: brain init");
134→    process.exit(1);
135→  }
136→  return config;
137→}
