 1→import { execSync } from "node:child_process";
 2→import { requireConfig } from "../config";
 3→import { BrainHttpClient } from "../http-client";
 4→
 5→/**
 6→ * brain check-commit
 7→ * Called by pre-commit git hook.
 8→ * Reads staged diff and checks for task completion, unlogged decisions, constraint violations.
 9→ */
10→export async function runCheckCommit(): Promise<void> {
11→  const config = await requireConfig();
12→  const client = new BrainHttpClient(config);
13→  const cwd = process.cwd();
14→
15→  let diff: string;
16→  let commitMessage: string;
17→  try {
18→    diff = execSync("git diff --cached", { encoding: "utf-8", cwd }).trim();
19→    try {
20→      commitMessage = execSync("cat .git/COMMIT_EDITMSG", { encoding: "utf-8", cwd }).trim();
21→    } catch {
22→      commitMessage = "";
23→    }
24→  } catch {
25→    return; // Not in a git repo or no staged changes
26→  }
27→
28→  if (!diff) return;
29→
30→  try {
31→    // Truncate for token budget
32→    const truncatedDiff = diff.length > 8000 ? diff.slice(0, 8000) : diff;
33→
34→    const result = await client.checkCommit({
35→      diff: truncatedDiff,
36→      commit_message: commitMessage,
37→    });
38→
39→    // Display findings to stderr (stdout is reserved for git hook protocol)
40→    for (const tc of result.task_completions) {
41→      if (tc.confidence >= 0.6) {
42→        process.stderr.write(`Brain: This commit may complete: ${tc.task_title}\n`);
43→      }
44→    }
45→    for (const d of result.unlogged_decisions) {
46→      process.stderr.write(`Brain: Unlogged decision: ${d.description}\n`);
47→    }
48→    for (const v of result.constraint_violations) {
49→      process.stderr.write(`Brain: Constraint violation (${v.severity}): ${v.violation}\n`);
50→    }
51→  } catch {
52→    // Never block commits on analysis failures
53→  }
54→}
55→
56→/**
57→ * brain log-commit
58→ * Deprecated. Commit ingestion is handled by GitHub webhook processing only.
59→ * Kept as a no-op for backward compatibility with existing post-commit hooks.
60→ */
61→export async function runLogCommit(): Promise<void> {
62→  process.stderr.write(
63→    "Brain: `log-commit` is disabled. GitHub webhook is the source of truth for commit ingestion.\n",
64→  );
65→}
